#include <stdio.h>

// Define transformation functions for R, G, B components
unsigned char transformR(unsigned char intensity) {
  return intensity;
}

unsigned char transformG(unsigned char intensity) {
  return intensity * intensity / 255;
}

unsigned char transformB(unsigned char intensity) {
  return sqrt(intensity * 255);
}

int main() {
  // Load input grayscale image
  unsigned char grayscaleImage[256][256];

  // Create output pseudocolor image
  unsigned char pseudocolorImage[256][256][3];

  // Apply transformation functions to each pixel
  for (int x = 0; x < 256; x++) {
    for (int y = 0; y < 256; y++) {
      pseudocolorImage[x][y][0] = transformR(grayscaleImage[x][y]);
      pseudocolorImage[x][y][1] = transformG(grayscaleImage[x][y]);
      pseudocolorImage[x][y][2] = transformB(grayscaleImage[x][y]);
    }
  }

  return 0;
}
